  export const filter: (
    filter: ConvertibleTypesStruct.Filter,
    value: ConvertibleTypesStruct,
  ) => boolean = (filter, value) => {
    if (
      filter.$identifier !== undefined &&
      !$filterIdentifier(filter.$identifier, value.$identifier())
    ) {
      return false;
    }
    if (
      filter.convertibleIri !== undefined &&
      !$filterIri(filter.convertibleIri, value.convertibleIri)
    ) {
      return false;
    }
    if (
      filter.convertibleIriNonEmptySet !== undefined &&
      !$filterArray<NamedNode, $IriFilter>($filterIri)(
        filter.convertibleIriNonEmptySet,
        value.convertibleIriNonEmptySet,
      )
    ) {
      return false;
    }
    if (
      filter.convertibleIriOption !== undefined &&
      !$filterMaybe<NamedNode, $IriFilter>($filterIri)(
        filter.convertibleIriOption,
        value.convertibleIriOption,
      )
    ) {
      return false;
    }
    if (
      filter.convertibleIriSet !== undefined &&
      !$filterArray<NamedNode, $IriFilter>($filterIri)(
        filter.convertibleIriSet,
        value.convertibleIriSet,
      )
    ) {
      return false;
    }
    if (
      filter.convertibleLiteral !== undefined &&
      !$filterLiteral(filter.convertibleLiteral, value.convertibleLiteral)
    ) {
      return false;
    }
    if (
      filter.convertibleLiteralNonEmptySet !== undefined &&
      !$filterArray<Literal, $LiteralFilter>($filterLiteral)(
        filter.convertibleLiteralNonEmptySet,
        value.convertibleLiteralNonEmptySet,
      )
    ) {
      return false;
    }
    if (
      filter.convertibleLiteralOption !== undefined &&
      !$filterMaybe<Literal, $LiteralFilter>($filterLiteral)(
        filter.convertibleLiteralOption,
        value.convertibleLiteralOption,
      )
    ) {
      return false;
    }
    if (
      filter.convertibleLiteralSet !== undefined &&
      !$filterArray<Literal, $LiteralFilter>($filterLiteral)(
        filter.convertibleLiteralSet,
        value.convertibleLiteralSet,
      )
    ) {
      return false;
    }
    if (
      filter.convertibleTerm !== undefined &&
      !$filterTerm(filter.convertibleTerm, value.convertibleTerm)
    ) {
      return false;
    }
    if (
      filter.convertibleTermNonEmptySet !== undefined &&
      !$filterArray<
        BlankNode | NamedNode | Literal,
        $TermFilter<BlankNode | NamedNode | Literal>
      >($filterTerm)(
        filter.convertibleTermNonEmptySet,
        value.convertibleTermNonEmptySet,
      )
    ) {
      return false;
    }
    if (
      filter.convertibleTermOption !== undefined &&
      !$filterMaybe<
        BlankNode | NamedNode | Literal,
        $TermFilter<BlankNode | NamedNode | Literal>
      >($filterTerm)(filter.convertibleTermOption, value.convertibleTermOption)
    ) {
      return false;
    }
    if (
      filter.convertibleTermSet !== undefined &&
      !$filterArray<
        BlankNode | NamedNode | Literal,
        $TermFilter<BlankNode | NamedNode | Literal>
      >($filterTerm)(filter.convertibleTermSet, value.convertibleTermSet)
    ) {
      return false;
    }
    return true;
  };

